async (params, browser) => {
  // Search Rotten Tomatoes
  await browser.open(`https://www.rottentomatoes.com/search?search=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('search-page-media-row, [class*=\'search-result\'], [data-qa=\'search-result\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('search-page-media-row, [class*="search-result"], [data-qa="search-result"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('a[data-qa="info-name"], [class*="title"] a, h2 a, a[slot="title"]'); const yearEl = el.querySelector('[data-qa="info-year"], [class*="year"], span[slot="year"]'); const tomatometerEl = el.querySelector('[data-qa="tomatometer"], rt-text[slot="criticsScore"], [class*="tomatometer"] span'); const audienceEl = el.querySelector('[data-qa="audience-score"], rt-text[slot="audienceScore"], [class*="audience"] span'); const imgEl = el.querySelector('img[data-qa="poster"], img[slot="image"], img'); const castEl = el.querySelector('[data-qa="cast"], [class*="cast"]'); const linkEl = el.querySelector('a[data-qa="info-name"], a[href*="/m/"], a[href*="/tv/"]'); results.push({ title: titleEl ? titleEl.textContent.trim() : '', year: yearEl ? yearEl.textContent.trim() : '', tomatometer: tomatometerEl ? tomatometerEl.textContent.trim() : '', audience_score: audienceEl ? audienceEl.textContent.trim() : '', cast: castEl ? castEl.textContent.trim().substring(0, 200) : '', image: imgEl ? imgEl.getAttribute('src') : '', url: linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.rottentomatoes.com' + linkEl.getAttribute('href')) : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
